head.script:
/**
 * 화 면 명 : 지사별손익(재무기준) 
 * 메뉴경로 : 회계/재무회계/일반회계/결산관리/
 * ASIS경로 : /dongwon-debis-engine/src/main/webapp/ac/fi/gnrlaccount/settmgnt/fi_204_03_17b.jsp
 * 작 성 자 : 정승혜
 * 작 업 일 : 2025-12-12
 * 수정이력  :
 *    - 2025-12-12      정승혜    최초작성
 *    - 2026-02-07      정승혜    기타수정
 * 메모 :
 * 양수 - Infinity   =  1
 * 음수 - Infinity   = -1
 * Infinity - 양수   =  1
 * Infinity - 음수   =  1
 * -Infinity - -Infinity = -1(NaN)
 * 조회조건 : 
 * 
 */

//전역변수
scwin.sDate                     = WebSquare.date.getCurrentServerDate();
scwin.closeMm                   = scwin.sDate.substring(0, 6);

//그리드 원본데이터
scwin.originData = {};

scwin.unitAmtFlag         =   1;  // 단위변경 금액 (0 으로 주면 NaN 발생)

scwin.onpageload = function() {

};

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {

};

// UDC값 초기화(scwin.onpageload 이후 세팅됨)
scwin.onUdcCompleted = function () {
    scwin.f_HeaderCreate();
    scwin.f_FieldClear();
    scwin.f_GetUnit();
}

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_search,[ica_srchCloseYm ]); //오브젝트초기화
    scwin.f_SetSrchDefault();
};

//-------------------------------------------------------------------------
// 조회 기본값 설정
//-------------------------------------------------------------------------
scwin.f_SetSrchDefault = function () {
    $c.gus.cfInitHidVal(tbl_search);
    ica_srchCloseYm .setValue(scwin.closeMm);
    scwin.f_GetVersion(); 		
    ed_srchAcctDeptCd.setValue('00000');
    ed_srchAcctDeptNm.setValue('전사');
    dma_search.set("distYn", "1")
    dma_search.set("bookClsCd", "604");
};

	//-------------------------------------------------------------------------
	// 조회 데이터셋 헤더를 생성
	//-------------------------------------------------------------------------
scwin.f_HeaderCreate = function() {
    // DataSet의 Header 정보 생성(TODO:TOBE 데이터맵으로 셋팅하므로 필요없음)
};

//-------------------------------------------------------------------------
// 조회 : 데이터를 조회한다.
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {
    // dma_search.setUseChangeInfo(false);

    dma_search.set("bizDomCd", ed_BizDomCd.getValue());
    $c.sbm.execute(sbm_search);
};

//-------------------------------------------------------------------------
// 팝업
//-------------------------------------------------------------------------
scwin.f_PopUp = async function(paramArray) {
    let codeObj = paramArray.pCode;
    let nameObj = paramArray.pName;

    udc_dept.cfCommonPopUp(scwin.udc_dept_callBackFunc, codeObj.getValue(), ""
                        ,paramArray.check, paramArray.pDispCnt
                        ,paramArray.pTitle, paramArray.pWidth
                        ,paramArray.pHidden, paramArray.pWhere
                        ,paramArray.pW, paramArray.pH
                        ,paramArray.pTop, paramArray.pLeft
                        ,paramArray.pExistTF, paramArray.pAllSearchTF
                        ,paramArray.pWtitleSearch)

};

scwin.udc_dept_callBackFunc = function(rtnList) {
    if (rtnList != null && rtnList[0] != "N/A") {
            ed_srchAcctDeptCd.setValue(rtnList[0]);
            ed_srchAcctDeptCd.options.hidVal = rtnList[0];
            ed_srchAcctDeptNm.setValue(rtnList[1]);
            dma_search.set("acctDeptLvl", rtnList[6]);
    } else {
            ed_srchAcctDeptCd.setValue("");
            ed_srchAcctDeptCd.options.hidVal = "";
            ed_srchAcctDeptNm.setValue("");
            dma_search.set("acctDeptLvl", 0);
    }
};

//-------------------------------------------------------------------------
// 팝업
//-------------------------------------------------------------------------
scwin.f_PopUp1 = async function(paramArray) {
    let codeObj = paramArray.pCode;
    let nameObj = paramArray.pName;

    udc_bizDomCdInfo.cfCommonPopUp(scwin.udc_bizDomCdInfo_callBackFunc, codeObj.getValue(), ""
                        ,paramArray.check, paramArray.pDispCnt
                        ,paramArray.pTitle, paramArray.pWidth
                        ,paramArray.pHidden, paramArray.pWhere
                        ,paramArray.pW, paramArray.pH
                        ,paramArray.pTop, paramArray.pLeft
                        ,paramArray.pExistTF, paramArray.pAllSearchTF
                        ,paramArray.pWtitleSearch)

};

scwin.udc_bizDomCdInfo_callBackFunc = function(rtnList) {
    if (rtnList != null && rtnList[0] != "N/A") {
        ed_BizDomCd.setValue(rtnList[0]);
        ed_BizDomCd.options.hidVal = rtnList[0];
        ed_BizDomNm.setValue(rtnList[1]);
    } else {
        ed_BizDomCd.setValue("");
        ed_BizDomCd.options.hidVal = "";
        ed_BizDomNm.setValue("");
    }
    if (rtnList != null ) {

    } else {

    }
};

//-------------------------------------------------------------------------
// 팝업 여부 검사
//-------------------------------------------------------------------------
scwin.f_IsPopUp = function(inObj, pairObj) {
    let inValue = inObj.getValue();
    let pairValue = pairObj.getValue();
    let hidInValue = inObj.options.hidVal;
    if(inValue == ""){
        pairObj.setValue("");
    }
    if (inValue == "" && pairValue == "") {
        inObj.options.hidVal = "";
    }
    if (inValue == hidInValue) return false;

    return true;
};

	//-------------------------------------------------------------------------
	// 팝업 이벤트에 따라 팝업창의 자동닫기 여부를 반환
	//-------------------------------------------------------------------------
scwin.f_EventCheck = function() {
    //udc
};

//-------------------------------------------------------------------------
// 부서코드팝업
//-------------------------------------------------------------------------
scwin.f_deptPopUp = function (check) {
    let paramArray = {};
    //<--<수정_070105_신종민> 귀속변경에 따른 병행처리 수정
    if ( ica_srchCloseYm .getValue().substring(0,4).trim() == '2006' ){
        udc_dept.setSelectId("retrieveAcctDeptCdInfoBef")
    }else{
        udc_dept.setSelectId("retrieveAcctDeptCdInfo")
    };			
    //->
    paramArray.pCode = ed_srchAcctDeptCd;
    paramArray.pName = ed_srchAcctDeptNm;
    paramArray.pW = "410";
    paramArray.check = check;

    scwin.f_PopUp(paramArray);
};

//-------------------------------------------------------------------------
// 사업영역코드팝업
//-------------------------------------------------------------------------
scwin.f_BizDomPopUp = function (check) {
    let paramArray = new Object();
    udc_bizDomCdInfo.setSelectId("retrieveBizDomCdInfo"); 
    //paramArray.pSelectID = 'retrieveBizDomCdInfo'		
    paramArray.pCode = ed_BizDomCd;
    paramArray.pName = ed_BizDomNm;
    paramArray.pW = "410";
    paramArray.check = check;

    scwin.f_PopUp1(paramArray);
};

//-------------------------------------------------------------------------
// 버전정보를 구한다.
//-------------------------------------------------------------------------
scwin.f_GetVersion = function () {
    sbm_ds_version.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC" +
                                            "&queryId=retrieveVersionInfo" +
                                            "&param1=" + ica_srchCloseYm.getValue().trim();
    $c.sbm.execute(sbm_ds_version);
};

//-------------------------------------------------------------------------
// 최종 Ver을 설정
//-------------------------------------------------------------------------
scwin.f_SetFinalVer = function () {
    if (ds_version.getRowCount() < 1) return;

    let index = 0;
    for (i = 0; i < ds_version.getRowCount(); i++) {
        if (ds_version.getCellData(i, "col3") == 1) {
            index = i;
            break;
        }
    }

    dma_search.set("ver", index);
};

//-------------------------------------------------------------------------
// 금액단위를 구한다.
//-------------------------------------------------------------------------
scwin.f_GetUnit = function () {
    sbm_ds_unit.action = "/cm.zz.RetrieveCodeCMD.do?grpCd=CO012&cd=&cdNm=";
    $c.sbm.execute(sbm_ds_unit);
};

//-------------------------------------------------------------------------
// Default Unit 을 설정
//-------------------------------------------------------------------------
scwin.f_SetDefaultUnit = function () {
    if (ds_unit.getRowCount() < 1) return;

    let index = 0;
    for (i = 0; i < ds_unit.getRowCount(); i++) {
        if (ds_unit.getCellData(i, "fltrCd1") == 1) {
            index = i;
            break;
        }
    }
    lc_unit.setSelectedIndex(index);
};

//-------------------------------------------------------------------------
// 그리드 컬럼의 금액단위를 설정한다.
//-------------------------------------------------------------------------
scwin.f_SetGridUnit = function () {
    const data = JSON.parse(JSON.stringify(scwin.originData))
    let unitAmt = lc_unit.getValue();

    if ( lc_unit.getValue() == "01" ) {  // 원
        scwin.unitAmtFlag = 1;
	} else if ( lc_unit.getValue() == "02" ) {  // 천원
        scwin.unitAmtFlag = 1000;
	} else if ( lc_unit.getValue() == "03" ) {  // 백만원
        scwin.unitAmtFlag = 1000000;
	} else if ( lc_unit.getValue() == "04" ) {  // 억
        scwin.unitAmtFlag = 100000000;
	}

    for (let i = 0; i < data.length; i++) {
        const row = data[i];

        const simpleCols = ["bfyyAvgAmt", "prePreYearRsltsAmt", "preYearRsltsAmt", "bfyyThisAmt", "preYearAccumRsltsAmt", 
                            "prePreRsltsAmt", "preRsltsAmt", "thisRsltsAmt", "threeMonthsSum", "thisAccumRsltsAmt", "prePreDiffer",
                            "preDiffer", "bfyyThisDiffer", "preAccumDiffer"];
        for (const col of simpleCols) {
            if (row.hasOwnProperty(col)) {
                //row[col] = Math.round((parseFloat(row[col]) || 0) / unitAmt);

                row[col] = scwin.roundAwayFromZero((parseFloat(row[col]) || 0) / unitAmt);
            }
        }

    };

    ds_master.setJSON(data);
    scwin.f_Rate()
};

	//-------------------------------------------------------------------------
	// 엑셀 Download
	//-------------------------------------------------------------------------
    // 엑셀다운 2+8+16
scwin.f_Export = async function(){
    if (ds_master.getRowCount() <= 0){
        await $c.win.alert(MSG_CM_WRN_002);
        return;
    }

    if (await $c.win.confirm("Excel로 다운로드 하시겠습니까?")) {
        let fileName = '지사별 손익_' + ed_srchAcctDeptCd.getValue() + "_" + ica_srchCloseYm.getValue() + "_ver_"
        let sheetTitle = ed_srchAcctDeptCd.getValue() + "(" + ica_srchCloseYm.getValue() + ")";
        let sheetTitle2 = '단위_' + lc_unit.getText();

        const infoArr = [
            {
            rowIndex : 0, 
            colIndex : 0, 
            rowSpan : 1,
            colSpan : 16, 
            text : sheetTitle , 
            textAlign : "center",
            fontSize : 18
            },
            {
            rowIndex : 3, 
            colIndex : 0, 
            rowSpan : 1,
            colSpan : 16, 
            text : sheetTitle2 , 
            textAlign : "right",
            fontSize : 12
            }
        ];
        const options = {
            fileName : fileName + ".xlsx", 
            sheetName : sheetTitle,
            startRowIndex : 4,
            startColumnIndex : 0,
            type : 1,

        };

        await $c.data.downloadGridViewExcel(gr_master, options, infoArr);
    }
};

//-------------------------------------------------------------------------
// 금액을 재설정한다.
//-------------------------------------------------------------------------
scwin.f_Rate = function () {	

    // 사용변수 선언
    let sellAmt       = 0;
    let sellAmt1      = 0;
    let sellAmt2      = 0;
    let sellAmt3      = 0;
    let sellAmt4      = 0;
    let sellAmt5      = 0;
    let sellAmt6      = 0;
    let sellAmt7      = 0;	
    let sellAmt8      = 0;
    let sellAmt9      = 0;	
    let sellAmt10     = 0;
    let sellAmt11     = 0;
    let sellAmt12     = 0;	
    let sellAmt13     = 0;
    let sellAmt14     = 0;
    let sellAmt15     = 0;	

    let sellCostSum   = 0;
    let sellCost1     = 0;
    let sellCost2     = 0;
    let sellCost3     = 0;
    let sellCost4     = 0;
    let sellCost5     = 0;
    let sellCost6     = 0;
    let sellCost7     = 0;
    let sellCost8     = 0;
    let sellCost9     = 0;
    let sellCost10    = 0;
    let sellCost11    = 0;
    let sellCost12    = 0;
    let sellCost13    = 0;
    let sellCost14    = 0;
    let sellCost15    = 0;

    let salesCostSum  = 0;
    let salesCost1    = 0;
    let salesCost2    = 0;
    let salesCost3    = 0;
    let salesCost4    = 0;
    let salesCost5    = 0;
    let salesCost6    = 0;
    let salesCost7    = 0;
    let salesCost8    = 0;
    let salesCost9    = 0;
    let salesCost10   = 0;
    let salesCost11   = 0;
    let salesCost12   = 0;
    let salesCost13   = 0;
    let salesCost14   = 0;
    let salesCost15   = 0;

    let mwoundSum     = 0;
    let mwound1       = 0;
    let mwound2       = 0;
    let mwound3       = 0;
    let mwound4       = 0;
    let mwound5       = 0;
    let mwound6       = 0;
    let mwound7       = 0;
    let mwound8       = 0;
    let mwound9       = 0;
    let mwound10      = 0;
    let mwound11      = 0;
    let mwound12      = 0;
    let mwound13      = 0;
    let mwound14      = 0;
    let mwound15      = 0;


    // 매출액, 매출원가, 영업이익, 경상이익을 구한다.
    for (i = 0; i < ds_master.getRowCount(); i++) {
        // 매출액
        if ( ds_master.getCellData(i, "mgntAcctCd") == "4100000") {
            sellAmt1 = parseInt(ds_master.getCellData(i, "bfyyAvgAmt"));
            sellAmt2 = parseInt(ds_master.getCellData(i, "bfyyThisAmt"));

            sellAmt3 = parseInt(ds_master.getCellData(i, "prePreRsltsAmt"));
            sellAmt4 = parseInt(ds_master.getCellData(i, "preRsltsAmt"));
            sellAmt5 = parseInt(ds_master.getCellData(i, "thisRsltsAmt"));

            sellAmt6 = parseInt(ds_master.getCellData(i, "bfyyThisDiffer"));
            sellAmt7 = parseInt(ds_master.getCellData(i, "thisPreDiffer"));
            sellAmt8 = parseInt(ds_master.getCellData(i, "threeMonthsSum"));

            sellAmt9 = parseInt(ds_master.getCellData(i, "prePreYearRsltsAmt"));
            sellAmt10 = parseInt(ds_master.getCellData(i, "preYearRsltsAmt"));
            sellAmt11 = parseInt(ds_master.getCellData(i, "preDiffer"));
            sellAmt12 = parseInt(ds_master.getCellData(i, "prePreDiffer"));

            sellAmt13 = parseInt(ds_master.getCellData(i, "preYearAccumRsltsAmt"));
            sellAmt14 = parseInt(ds_master.getCellData(i, "thisAccumRsltsAmt"));
            sellAmt15 = parseInt(ds_master.getCellData(i, "preAccumDiffer"));

        }

        // 매출원가		
        if ( ds_master.getCellData(i, "mgntAcctCd") == "4200000" ) {
            sellCost1 = parseInt(ds_master.getCellData(i, "bfyyAvgAmt"));
            sellCost2 = parseInt(ds_master.getCellData(i, "bfyyThisAmt"));

            sellCost3 = parseInt(ds_master.getCellData(i, "prePreRsltsAmt"));
            sellCost4 = parseInt(ds_master.getCellData(i, "preRsltsAmt"));
            sellCost5 = parseInt(ds_master.getCellData(i, "thisRsltsAmt"));

            sellCost6 = parseInt(ds_master.getCellData(i, "bfyyThisDiffer"));
            sellCost7 = parseInt(ds_master.getCellData(i, "thisPreDiffer"));
            sellCost8 = parseInt(ds_master.getCellData(i, "threeMonthsSum"));

            sellCost9 = parseInt(ds_master.getCellData(i, "prePreYearRsltsAmt"));
            sellCost10 = parseInt(ds_master.getCellData(i, "preYearRsltsAmt"));
            sellCost11 = parseInt(ds_master.getCellData(i, "preDiffer"));
            sellCost12 = parseInt(ds_master.getCellData(i, "prePreDiffer"));

            sellCost13 = parseInt(ds_master.getCellData(i, "preYearAccumRsltsAmt"));
            sellCost14 = parseInt(ds_master.getCellData(i, "thisAccumRsltsAmt"));
            sellCost15 = parseInt(ds_master.getCellData(i, "preAccumDiffer"));
        }

        // 영업이익
        if ( ds_master.getCellData(i, "mgntAcctCd") == "5900000" ) {
            salesCost1 = parseInt(ds_master.getCellData(i, "bfyyAvgAmt"));
            salesCost2 = parseInt(ds_master.getCellData(i, "bfyyThisAmt"));

            salesCost3 = parseInt(ds_master.getCellData(i, "prePreRsltsAmt"));
            salesCost4 = parseInt(ds_master.getCellData(i, "preRsltsAmt"));
            salesCost5 = parseInt(ds_master.getCellData(i, "thisRsltsAmt"));

            salesCost6 = parseInt(ds_master.getCellData(i, "bfyyThisDiffer"));
            salesCost7 = parseInt(ds_master.getCellData(i, "thisPreDiffer")); 
            salesCost8 = parseInt(ds_master.getCellData(i, "threeMonthsSum")); 

            salesCost9 = parseInt(ds_master.getCellData(i, "prePreYearRsltsAmt"));
            salesCost10 = parseInt(ds_master.getCellData(i, "preYearRsltsAmt")); 
            salesCost11 = parseInt(ds_master.getCellData(i, "preDiffer"));
            salesCost12 = parseInt(ds_master.getCellData(i, "prePreDiffer")); 

            salesCost13 = parseInt(ds_master.getCellData(i, "preYearAccumRsltsAmt"));
            salesCost14 = parseInt(ds_master.getCellData(i, "thisAccumRsltsAmt"));
            salesCost15 = parseInt(ds_master.getCellData(i, "preAccumDiffer"));
        }

        // 경상이익
        if ( ds_master.getCellData(i, "mgntAcctCd") == "6700000" ) {
            mwound1 = parseInt(ds_master.getCellData(i, "bfyyAvgAmt"));
            mwound2 = parseInt(ds_master.getCellData(i, "bfyyThisAmt"));

            mwound3 = parseInt(ds_master.getCellData(i, "prePreRsltsAmt"));
            mwound4 = parseInt(ds_master.getCellData(i, "preRsltsAmt"));
            mwound5 = parseInt(ds_master.getCellData(i, "thisRsltsAmt"));

            mwound6 = parseInt(ds_master.getCellData(i, "bfyyThisDiffer"));
            mwound7 = parseInt(ds_master.getCellData(i, "thisPreDiffer"));  
            mwound8 = parseInt(ds_master.getCellData(i, "threeMonthsSum")); 

            mwound9 = parseInt(ds_master.getCellData(i, "prePreYearRsltsAmt"));
            mwound10 = parseInt(ds_master.getCellData(i, "preYearRsltsAmt")); 
            mwound11 = parseInt(ds_master.getCellData(i, "preDiffer"));
            mwound12 = parseInt(ds_master.getCellData(i, "prePreDiffer")); 

            mwound13 = parseInt(ds_master.getCellData(i, "preYearAccumRsltsAmt"));
            mwound14 = parseInt(ds_master.getCellData(i, "thisAccumRsltsAmt"));
            mwound15 = parseInt(ds_master.getCellData(i, "preAccumDiffer"));
        }  
    }

    // 매출원가율, 영업이익율, 경상이익율을 구한다.
    for (i = 0; i < ds_master.getRowCount(); i++) {

        // 매출원가율
        if (ds_master.getCellData(i, "mgntAcctCd") == "9300001") {
            ds_master.setCellData(i, "bfyyAvgAmt", Math.round((sellAmt1 === 0 ? 0 : (sellCost1 / sellAmt1) * 100)));
            ds_master.setCellData(i, "bfyyThisAmt", Math.round((sellAmt2 === 0 ? 0 : (sellCost2 / sellAmt2) * 100)));

            //당기-전전월
            ds_master.setCellData(i, "prePreRsltsAmt", Math.round((sellAmt3 === 0 ? 0 : (sellCost3 / sellAmt3) * 100)));
            if(parseInt(sellAmt3) === 0){
                if(sellCost3 > 0){
                    ds_master.setCellData(i, "prePreRsltsAmt", 1);
                }else{
                    ds_master.setCellData(i, "prePreRsltsAmt", -1);
                }
            }

            //당기-전월
            ds_master.setCellData(i, "preRsltsAmt", Math.round((sellAmt4 === 0 ? 0 : (sellCost4 / sellAmt4) * 100)));
            if(parseInt(sellAmt4) === 0){
                if(sellCost4 > 0){
                    ds_master.setCellData(i, "preRsltsAmt", 1);
                }else{
                    ds_master.setCellData(i, "preRsltsAmt", -1);
                }
            }

            //당기-당월
            ds_master.setCellData(i, "thisRsltsAmt", Math.round((sellAmt5 === 0 ? 0 : (sellCost5 / sellAmt5) * 100)));
            if(parseInt(sellAmt5) === 0){
                if(sellCost5 > 0){
                    ds_master.setCellData(i, "thisRsltsAmt", 1);
                }else{
                    ds_master.setCellData(i, "thisRsltsAmt", -1);
                }
            }

            //당기-3개월누적
            ds_master.setCellData(i, "threeMonthsSum", Math.round((sellAmt8 === 0 ? 0 : (sellCost8 / sellAmt8) * 100)));
            if(parseInt(sellAmt8) === 0){
                if(sellCost8 > 0){
                    ds_master.setCellData(i, "threeMonthsSum", 1);
                }else{
                    ds_master.setCellData(i, "threeMonthsSum", -1);
                }
            }

            ds_master.setCellData(i, "prePreYearRsltsAmt", Math.round((sellAmt9 === 0 ? 0 : (sellCost9 / sellAmt9) * 100)));
            ds_master.setCellData(i, "preYearRsltsAmt", Math.round((sellAmt10 === 0 ? 0 : (sellCost10 / sellAmt10) * 100)));

            ds_master.setCellData(i, "preYearAccumRsltsAmt", Math.round((sellAmt13 === 0 ? 0 : (sellCost13 / sellAmt13) * 100)));

            //당기-당기누적
            ds_master.setCellData(i, "thisAccumRsltsAmt", Math.round((sellAmt14 === 0 ? 0 : (sellCost14 / sellAmt14) * 100)));
            if(parseInt(sellAmt14) === 0){
                if(sellCost14 > 0){
                    ds_master.setCellData(i, "thisAccumRsltsAmt", 1);
                }else{
                    ds_master.setCellData(i, "thisAccumRsltsAmt", -1);
                }
            }

            //증감액-전전월
            ds_master.setCellData(i, "prePreDiffer", ds_master_temp.getCellData(i, "prePreRsltsAmt") - ds_master_temp.getCellData(i, "prePreYearRsltsAmt"));
            if(parseInt(sellAmt3) === 0){
                if(sellCost3 > 0){
                    ds_master.setCellData(i, "prePreDiffer", 1);
                }else{
                    ds_master.setCellData(i, "prePreDiffer", -1);
                }
            }

            //증감액-전월
