scwin.sbm_search_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    ds_master_temp.setJSON(ds_master.getAllJSON());

    let rowCnt = ds_master.getRowCount();
    totalRows.setValue(ds_master.getRowCount());
    if (rowCnt == 0) { 
        await $c.win.alert(MSG_CM_WRN_002);
    }else{
        scwin.originData  = ds_master.getAllJSON();
        scwin.f_SetGridUnit();
    }
};

scwin.sbm_ds_unit_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    scwin.f_SetDefaultUnit();
};

scwin.sbm_ds_version_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    scwin.f_SetFinalVer();
};


scwin.ica_srchCloseYm_onblur = function (e) {
    scwin.f_GetVersion();
};

scwin.lc_unit_onviewchange = function (info) {
    scwin.f_SetGridUnit();
};

scwin.udc_dept_onblurCodeEvent = function (e) {

    if (ed_srchAcctDeptCd.getValue() != ""){
	    //if (scwin.f_IsPopUp(ed_srchAcctDeptCd, ed_srchAcctDeptNm) == false) return;
	    scwin.f_deptPopUp("T");
    }else{
        ed_srchAcctDeptNm.setValue("");
        ed_srchAcctDeptCd.options.hidVal = "";
    }
};

scwin.udc_bizDomCdInfo_onblurCodeEvent = function (e) {
