};

scwin.udc_bizDomCdInfo_onclickEvent = function (e) {
    scwin.f_BizDomPopUp("F");
};

scwin.roundAwayFromZero = function(x) {
  if (!Number.isFinite(x)) return 0;
  return x >= 0 ? Math.round(x) : -Math.round(-x);
}

// 금액변경 함수 추가
scwin.f_changeUnitAmt = function(val) {
    if ( val == 0 ) return "-0";  // 0 이면 -0 표현

    let ret = Math.round( parseInt(val) / scwin.unitAmtFlag);

    // 음수 처리 :
    //   60 만 / 원     양수 60만, 음수 -60만
    //   60 만 / 1000   양수 600 , 음수 -600
    //   60 만 / 백만   양수 1, 음수 -1
    //   60 만 / 1억    양수 0, 음수 -0  (엑셀 양수 0, 음수 0)

    // 음수의 round 가 0 이면 -0 으로 표현
    if ( val < 0 ) {
         if ( ret == 0 ) return "-0";
    }

    return $c.num.formatNumber(ret);
}
